ruleSearch.bookList:
.booklist li
<js>
result.toArray().slice(0,2).map(o=>{
    var detail = String(o.select('h3 a').attr('href')).replace(/^\//, baseUrl.match(/(.+?\/\/[^\/]+\/)/)[1]);
    var J = org.jsoup.Jsoup.parse(java.ajax(detail));
    var oText = selector =>o.select(selector).text().trim();   
    var jText = selector =>String(J.select(selector).text().trim()); 
    return {
       name:  oText('h3 a'),
       author:jText('.info dd:eq(1)'),
       tags:  jText('.info dd:eq(3)'),
       num: jText('.info dd:eq(5)'),
       latest:jText('.tlist li:eq(0)'),
       intro: jText('#abstract-text p').replace(/.+：/, ''),
       cover: o.select('img').attr('src'),
       catalogUrl: J.select('.ft a').attr('href')
    }
});
</js>
